import{C as h,S as o}from"./chunks/theme.Bv0bhO78.js";import{o as i,c as n,j as t,a as d,E as a,w as e,ae as l}from"./chunks/framework.PV3mkH3Y.js";const q=JSON.parse('{"title":"ออกแบบสถานี","description":"","frontmatter":{},"headers":[],"relativePath":"guide/station-designer.md","filePath":"guide/station-designer.md"}'),s={name:"guide/station-designer.md"},g=Object.assign(s,{setup(b){return(c,r)=>(i(),n("div",null,[r[3]||(r[3]=t("h1",{id:"ออกแบบสถานี",tabindex:"-1"},[d("ออกแบบสถานี "),t("a",{class:"header-anchor",href:"#ออกแบบสถานี","aria-label":'Permalink to "ออกแบบสถานี"'},"​")],-1)),a(h,{title:"ออกแบบสถานีคืออะไร?",variant:"blue"},{default:e(()=>[...r[0]||(r[0]=[d(" เครื่องมือสร้างหน้าจอสำหรับแต่ละสถานีงานในโรงงาน — คุณสามารถลาก-วางบล็อกต่าง ๆ เพื่อสร้างหน้าจอที่เหมาะกับงานของสถานีนั้น ๆ ได้เองโดยไม่ต้องเขียนโปรแกรม ",-1)])]),_:1}),r[4]||(r[4]=l('<div class="warning custom-block"><p class="custom-block-title">สิทธิ์การเข้าถึง</p><p>หน้าออกแบบสถานีเข้าถึงได้เฉพาะ <strong>Admin</strong> เท่านั้น</p></div><h2 id="ภาพรวม" tabindex="-1">ภาพรวม <a class="header-anchor" href="#ภาพรวม" aria-label="Permalink to &quot;ภาพรวม&quot;">​</a></h2><p>ระบบแบ่งออกเป็น 2 ส่วนหลัก:</p><ul><li><strong>คลังแบบสถานี</strong> — แสดงรายการแบบสถานีที่สร้างไว้ทั้งหมด</li><li><strong>ตัวแก้ไขแบบสถานี</strong> — หน้าออกแบบแบบลาก-วาง</li></ul><h2 id="วิธีสร้างแบบสถานีใหม่" tabindex="-1">วิธีสร้างแบบสถานีใหม่ <a class="header-anchor" href="#วิธีสร้างแบบสถานีใหม่" aria-label="Permalink to &quot;วิธีสร้างแบบสถานีใหม่&quot;">​</a></h2>',5)),a(o,null,{default:e(()=>[...r[1]||(r[1]=[t("div",{class:"step","data-step":"1"},[t("h4",null,"เข้าหน้าออกแบบสถานี"),t("p",null,[d("ไปที่เมนู "),t("strong",null,"สถานี"),d(" → "),t("strong",null,"ออกแบบสถานี"),d(" ระบบจะแสดงรายการแบบสถานีทั้งหมดที่มีอยู่")])],-1),t("div",{class:"step","data-step":"2"},[t("h4",null,"สร้างแบบใหม่"),t("p",null,[d("กดปุ่ม "),t("strong",null,"+ สร้างแบบสถานีใหม่"),d(' แล้วกรอกชื่อ ตัวอย่างเช่น "สถานีตัดกระจก" หรือ "สถานีรับบิล"')])],-1),t("div",{class:"step","data-step":"3"},[t("h4",null,"เปิดหน้าออกแบบ"),t("p",null,[d("กดปุ่ม "),t("strong",null,"แก้ไข"),d(" บนแบบที่สร้างขึ้น ระบบจะเปิดหน้าออกแบบแบบลาก-วาง")])],-1),t("div",{class:"step","data-step":"4"},[t("h4",null,"เพิ่มบล็อก"),t("p",null,"คลิกบล็อกจากแผงด้านซ้าย หรือลากมาวางบนพื้นที่ออกแบบ จากนั้นปรับค่าต่าง ๆ ที่แผงด้านขวา")],-1),t("div",{class:"step","data-step":"5"},[t("h4",null,"บันทึก"),t("p",null,[d("กดปุ่ม "),t("strong",null,"บันทึก"),d(" ที่แถบด้านบน แบบสถานีจะถูกบันทึกและนำไปใช้กับสถานีได้ทันที")])],-1)])]),_:1}),r[5]||(r[5]=l('<h2 id="หน้าตัวแก้ไข" tabindex="-1">หน้าตัวแก้ไข <a class="header-anchor" href="#หน้าตัวแก้ไข" aria-label="Permalink to &quot;หน้าตัวแก้ไข&quot;">​</a></h2><p>หน้าออกแบบแบ่งเป็น 3 ส่วน:</p><table tabindex="0"><thead><tr><th>ส่วน</th><th>รายละเอียด</th></tr></thead><tbody><tr><td><strong>แผงบล็อก (ซ้าย)</strong></td><td>รายการบล็อกทั้งหมดที่ใช้ได้ คลิกหรือลากมาวางในพื้นที่ออกแบบ</td></tr><tr><td><strong>พื้นที่ออกแบบ (กลาง)</strong></td><td>พื้นที่แสดงตัวอย่างหน้าจอ ลาก ย้าย จัดเรียงบล็อกได้ตามต้องการ</td></tr><tr><td><strong>แผงตั้งค่า (ขวา)</strong></td><td>ค่าต่าง ๆ ของบล็อกที่คลิกเลือกอยู่ เช่น ข้อความ สี ขนาด ฯลฯ</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">คีย์ลัด</p><ul><li><strong>Ctrl+Z</strong> (Windows) / <strong>Cmd+Z</strong> (Mac) — เลิกทำ</li><li><strong>Ctrl+Y</strong> (Windows) / <strong>Cmd+Shift+Z</strong> (Mac) — ทำซ้ำ</li></ul></div><hr><h2 id="บล็อกทั้งหมด" tabindex="-1">บล็อกทั้งหมด <a class="header-anchor" href="#บล็อกทั้งหมด" aria-label="Permalink to &quot;บล็อกทั้งหมด&quot;">​</a></h2><p>บล็อกแบ่งออกเป็น 5 หมวด ดังนี้</p><hr><h3 id="🔲-บล็อกโครงสร้าง" tabindex="-1">🔲 บล็อกโครงสร้าง <a class="header-anchor" href="#🔲-บล็อกโครงสร้าง" aria-label="Permalink to &quot;🔲 บล็อกโครงสร้าง&quot;">​</a></h3><p>บล็อกกลุ่มนี้ใช้จัดวางโครงร่างหน้าจอ ก่อนเพิ่มเนื้อหา</p><hr><h4 id="กล่องพื้นที่-section" tabindex="-1">กล่องพื้นที่ (Section) <a class="header-anchor" href="#กล่องพื้นที่-section" aria-label="Permalink to &quot;กล่องพื้นที่ (Section)&quot;">​</a></h4><p>กล่องขนาดใหญ่ที่ใช้จัดกลุ่มบล็อกอื่น ๆ เข้าด้วยกัน เช่น จัดกลุ่มส่วน &quot;ข้อมูลออเดอร์&quot; แยกจากส่วน &quot;รายการชิ้นงาน&quot; ตั้งสีพื้นหลังเพื่อให้แยกส่วนได้ชัดเจน</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>สีพื้นหลัง</td><td>ขาว / เทา / น้ำเงินอ่อน / เขียวอ่อน / เหลืองอ่อน</td></tr><tr><td>ระยะห่างรอบใน</td><td>ไม่มี / เล็ก / กลาง / ใหญ่</td></tr></tbody></table><hr><h4 id="วางเคียงกัน-twocolumns" tabindex="-1">วางเคียงกัน (TwoColumns) <a class="header-anchor" href="#วางเคียงกัน-twocolumns" aria-label="Permalink to &quot;วางเคียงกัน (TwoColumns)&quot;">​</a></h4><p>แบ่งพื้นที่ออกเป็น 2–4 ช่องแนวตั้งเคียงกัน เหมาะเมื่อต้องการวางบล็อกสองอย่างไว้ข้างกัน เช่น &quot;รายการออเดอร์&quot; อยู่ซ้าย และ &quot;รายละเอียดชิ้นงาน&quot; อยู่ขวา</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>จำนวนช่อง</td><td>2 / 3 / 4</td></tr><tr><td>อัตราส่วนความกว้าง</td><td>เท่ากัน / ซ้ายกว้างกว่า (2:1) / ขวากว้างกว่า (1:2) / ซ้ายกว้างมาก (3:1) / ขวากว้างมาก (1:3)</td></tr><tr><td>ช่องว่างระหว่างคอลัมน์</td><td>เล็ก / กลาง / ใหญ่ / ใหญ่มาก</td></tr></tbody></table><hr><h4 id="คอลัมน์-column" tabindex="-1">คอลัมน์ (Column) <a class="header-anchor" href="#คอลัมน์-column" aria-label="Permalink to &quot;คอลัมน์ (Column)&quot;">​</a></h4><p>กล่องเรียงแนวตั้ง ใช้วางบล็อกซ้อนกันภายในช่อง &quot;วางเคียงกัน&quot; บล็อกนี้จะสร้างขึ้นอัตโนมัติเมื่อเพิ่ม &quot;วางเคียงกัน&quot;</p><hr><h4 id="เส้นคั่น-divider" tabindex="-1">เส้นคั่น (Divider) <a class="header-anchor" href="#เส้นคั่น-divider" aria-label="Permalink to &quot;เส้นคั่น (Divider)&quot;">​</a></h4><p>เส้นแนวนอนสำหรับแบ่งส่วนเนื้อหาให้ดูเป็นระเบียบ</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ระยะห่างด้านบน-ล่าง</td><td>เล็ก / กลาง / ใหญ่</td></tr><tr><td>รูปแบบเส้น</td><td>ทึบ / ประ</td></tr></tbody></table><hr><h4 id="พื้นที่ว่าง-spacer" tabindex="-1">พื้นที่ว่าง (Spacer) <a class="header-anchor" href="#พื้นที่ว่าง-spacer" aria-label="Permalink to &quot;พื้นที่ว่าง (Spacer)&quot;">​</a></h4><p>ช่องว่างแนวตั้ง ใช้เพิ่มระยะห่างระหว่างบล็อก กำหนดความสูงเป็นตัวเลข เช่น 16 หรือ 32</p><hr><h3 id="📝-บล็อกข้อความและแสดงผล" tabindex="-1">📝 บล็อกข้อความและแสดงผล <a class="header-anchor" href="#📝-บล็อกข้อความและแสดงผล" aria-label="Permalink to &quot;📝 บล็อกข้อความและแสดงผล&quot;">​</a></h3><p>บล็อกกลุ่มนี้ใช้แสดงข้อความและข้อมูล</p><hr><h4 id="หัวเรื่อง-heading" tabindex="-1">หัวเรื่อง (Heading) <a class="header-anchor" href="#หัวเรื่อง-heading" aria-label="Permalink to &quot;หัวเรื่อง (Heading)&quot;">​</a></h4><p>แสดงข้อความหัวเรื่องขนาดใหญ่ ใช้ตั้งชื่อส่วนต่าง ๆ ในหน้าจอ นอกจากข้อความตายตัว ยังสามารถแสดงข้อมูลจากออเดอร์หรือบิลที่เลือกอยู่ได้โดยอัตโนมัติ</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ข้อความ</td><td>พิมพ์ข้อความที่ต้องการแสดง</td></tr><tr><td>ขนาด</td><td>ใหญ่สุด / ใหญ่ / กลาง / เล็ก</td></tr><tr><td>การจัดตำแหน่ง</td><td>ซ้าย / กลาง / ขวา</td></tr><tr><td>สี</td><td>ปกติ / เน้น / จาง / น้ำเงิน / เขียว</td></tr><tr><td>รูปแบบ</td><td>ปกติ / หนา / เอียง / หนา+เอียง</td></tr><tr><td>แสดงข้อมูลอัตโนมัติ</td><td>เลือกข้อมูลที่ต้องการดึงมาแสดง เช่น ชื่อลูกค้า, รหัสออเดอร์ (ดูตารางข้อมูลที่แสดงได้ด้านล่าง)</td></tr></tbody></table><hr><h4 id="ข้อความ-paragraph" tabindex="-1">ข้อความ (Paragraph) <a class="header-anchor" href="#ข้อความ-paragraph" aria-label="Permalink to &quot;ข้อความ (Paragraph)&quot;">​</a></h4><p>แสดงข้อความเนื้อหาทั่วไป เหมาะสำหรับคำอธิบาย หมายเหตุ หรือข้อความแนะนำขั้นตอนให้พนักงาน</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ข้อความ</td><td>พิมพ์ข้อความที่ต้องการ</td></tr><tr><td>การจัดตำแหน่ง</td><td>ซ้าย / กลาง / ขวา</td></tr><tr><td>ขนาด</td><td>เล็ก / ปกติ / ใหญ่</td></tr><tr><td>แสดงข้อมูลอัตโนมัติ</td><td>เลือกข้อมูลที่ต้องการดึงมาแสดงแทนข้อความ</td></tr></tbody></table><hr><h4 id="ป้ายสถานะ-badge" tabindex="-1">ป้ายสถานะ (Badge) <a class="header-anchor" href="#ป้ายสถานะ-badge" aria-label="Permalink to &quot;ป้ายสถานะ (Badge)&quot;">​</a></h4><p>แสดงป้ายข้อความสั้น ๆ รูปแบบมน ๆ เหมาะใช้แสดงสถานะหรือข้อมูลเน้น เช่น &quot;รออนุมัติ&quot; หรือ &quot;เสร็จแล้ว&quot;</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ข้อความ</td><td>ข้อความบนป้าย</td></tr><tr><td>สี</td><td>ปกติ (เทา) / เขียว / เหลือง / แดง / น้ำเงิน</td></tr><tr><td>แสดงข้อมูลอัตโนมัติ</td><td>เลือกข้อมูลสถานะจากออเดอร์หรือชิ้นงาน</td></tr></tbody></table><hr><h4 id="การ์ดข้อมูล-infocard" tabindex="-1">การ์ดข้อมูล (InfoCard) <a class="header-anchor" href="#การ์ดข้อมูล-infocard" aria-label="Permalink to &quot;การ์ดข้อมูล (InfoCard)&quot;">​</a></h4><p>การ์ดแสดงข้อมูลสำคัญ มีเส้นสีด้านซ้ายเพื่อเน้น เหมาะสำหรับแสดงข้อมูลที่พนักงานต้องสังเกตก่อนทำงาน เช่น ข้อความเตือน หรือรายละเอียดพิเศษของออเดอร์</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>หัวข้อ</td><td>ข้อความบรรทัดแรก (ตัวหนา)</td></tr><tr><td>หัวข้อย่อย</td><td>ข้อความบรรทัดที่สอง (ตัวเล็กกว่า)</td></tr><tr><td>เนื้อหา</td><td>รายละเอียดหลัก</td></tr><tr><td>สีเส้นเน้น</td><td>น้ำเงิน / เขียว / ส้ม / ม่วง / แดง / เทา</td></tr></tbody></table><hr><h4 id="ตัวบ่งชี้สถานะ-statusindicator" tabindex="-1">ตัวบ่งชี้สถานะ (StatusIndicator) <a class="header-anchor" href="#ตัวบ่งชี้สถานะ-statusindicator" aria-label="Permalink to &quot;ตัวบ่งชี้สถานะ (StatusIndicator)&quot;">​</a></h4><p>แสดงสถานะในรูปแบบต่าง ๆ เหมาะสำหรับแสดงสถานะของชิ้นงานหรือออเดอร์ที่เลือกอยู่</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>ข้อความที่แสดงคู่กับสถานะ</td></tr><tr><td>รูปแบบ</td><td>แบบกลม / แบบป้าย / แบบจุด / แบบแท็ก</td></tr><tr><td>แสดงข้อมูลอัตโนมัติ</td><td>เลือกข้อมูลสถานะ</td></tr></tbody></table><hr><h3 id="🖊️-บล็อกรับข้อมูล" tabindex="-1">🖊️ บล็อกรับข้อมูล <a class="header-anchor" href="#🖊️-บล็อกรับข้อมูล" aria-label="Permalink to &quot;🖊️ บล็อกรับข้อมูล&quot;">​</a></h3><p>บล็อกกลุ่มนี้ใช้รับข้อมูลจากผู้ใช้ เช่น การกรอก การเลือก และการสแกน</p><hr><h4 id="ช่องกรอกข้อมูล-inputfield" tabindex="-1">ช่องกรอกข้อมูล (InputField) <a class="header-anchor" href="#ช่องกรอกข้อมูล-inputfield" aria-label="Permalink to &quot;ช่องกรอกข้อมูล (InputField)&quot;">​</a></h4><p>ช่องให้พนักงานพิมพ์ข้อมูล เช่น จำนวน หมายเหตุ หรือวันที่</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>ข้อความที่แสดงเหนือช่องกรอก เช่น &quot;จำนวน&quot;</td></tr><tr><td>ข้อความตัวอย่าง</td><td>ข้อความแสดงจางๆ ก่อนกรอก เช่น &quot;กรอกจำนวนชิ้นงาน&quot;</td></tr><tr><td>ประเภท</td><td>ข้อความ / ตัวเลข / วันที่ / อีเมล / เบอร์โทร</td></tr><tr><td>บังคับกรอก</td><td>เปิด = ห้ามบันทึกถ้ายังไม่กรอก</td></tr><tr><td>ชื่ออ้างอิง</td><td>ชื่อสำหรับระบบใช้จดจำข้อมูลในช่องนี้ เพื่อให้ปุ่มหรือบล็อกอื่นนำไปใช้ต่อได้ ตั้งชื่อสั้น ๆ ภาษาอังกฤษ เช่น <code>note</code> หรือ <code>quantity</code></td></tr><tr><td>ค่าเริ่มต้น</td><td>ข้อมูลที่ระบบกรอกให้อัตโนมัติก่อนที่พนักงานจะแก้ไข</td></tr></tbody></table><hr><h4 id="ช่องเลือกจากรายการ-selectfield" tabindex="-1">ช่องเลือกจากรายการ (SelectField) <a class="header-anchor" href="#ช่องเลือกจากรายการ-selectfield" aria-label="Permalink to &quot;ช่องเลือกจากรายการ (SelectField)&quot;">​</a></h4><p>Dropdown ให้พนักงานเลือกข้อมูลจากรายการ ระบบจะโหลดรายการล่าสุดจากข้อมูลในระบบให้อัตโนมัติ เมื่อเลือกรายการใด ข้อมูลทั้งหมดของรายการนั้นจะถูกนำมาใช้ในบล็อกอื่น ๆ ในหน้านี้ได้ทันที</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>ข้อความที่แสดงเหนือ Dropdown เช่น &quot;เลือกบิล&quot;</td></tr><tr><td>ชนิดรายการ</td><td>ดูตารางด้านล่าง</td></tr><tr><td>ชื่ออ้างอิง</td><td>ชื่อสำหรับระบบใช้จดจำว่าเลือกอะไร</td></tr><tr><td>กรองจากช่องอื่น</td><td>เชื่อมกับช่องเลือกอื่นในหน้านี้เพื่อกรองรายการ เช่น เลือกลูกค้าก่อน แล้วรายการออเดอร์จะแสดงเฉพาะของลูกค้านั้น</td></tr></tbody></table><p><strong>ชนิดรายการที่เลือกได้:</strong></p><table tabindex="0"><thead><tr><th>ชนิดรายการ</th><th>แสดงอะไร</th></tr></thead><tbody><tr><td>ออเดอร์</td><td>รายการออเดอร์ทั้งหมดในระบบ</td></tr><tr><td>บิล</td><td>รายการบิลที่ยังไม่ได้สร้างออเดอร์</td></tr><tr><td>วัสดุ</td><td>รายการวัสดุ/กระจกในคลัง</td></tr><tr><td>พนักงาน</td><td>รายชื่อพนักงานทั้งหมด</td></tr><tr><td>ลูกค้า</td><td>รายชื่อลูกค้าทั้งหมด</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">เลือกบิลแล้วข้อมูลเข้าอัตโนมัติ</p><p>เมื่อพนักงานเลือกบิลจาก Dropdown ระบบจะดึงข้อมูลบิลนั้นมาทั้งหมด — ชื่อลูกค้า จำนวน รายละเอียด — เพื่อให้บล็อกอื่นในหน้านี้แสดงผลและปุ่มนำไปสร้างออเดอร์ได้ทันที</p></div><hr><h4 id="ช่องกรอกข้อความยาว-textareafield" tabindex="-1">ช่องกรอกข้อความยาว (TextAreaField) <a class="header-anchor" href="#ช่องกรอกข้อความยาว-textareafield" aria-label="Permalink to &quot;ช่องกรอกข้อความยาว (TextAreaField)&quot;">​</a></h4><p>ช่องให้พนักงานพิมพ์ข้อความหลายบรรทัด เหมาะสำหรับบันทึก คำอธิบายงาน หรือหมายเหตุพิเศษ</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>ข้อความที่แสดงเหนือช่อง</td></tr><tr><td>ข้อความตัวอย่าง</td><td>ข้อความแสดงจางๆ ก่อนกรอก</td></tr><tr><td>ความสูงช่อง</td><td>จำนวนแถว เช่น 3 = สูงพอกรอก 3 บรรทัด</td></tr><tr><td>ชื่ออ้างอิง</td><td>ชื่อสำหรับระบบใช้จดจำข้อมูล</td></tr></tbody></table><hr><h4 id="ปุ่มกด-buttonblock" tabindex="-1">ปุ่มกด (ButtonBlock) <a class="header-anchor" href="#ปุ่มกด-buttonblock" aria-label="Permalink to &quot;ปุ่มกด (ButtonBlock)&quot;">​</a></h4><p>ปุ่มที่พนักงานกดเพื่อดำเนินการต่าง ๆ เช่น บันทึกข้อมูล สร้างออเดอร์ หรือไปยังหน้าอื่น</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ข้อความบนปุ่ม</td><td>ข้อความที่แสดงบนปุ่ม เช่น &quot;ยืนยันออเดอร์&quot;</td></tr><tr><td>รูปแบบ</td><td>น้ำเงิน (หลัก) / ขอบ (ไม่เติม) / แดง (ลบ) / เขียว (สำเร็จ)</td></tr><tr><td>ขนาด</td><td>เล็ก / กลาง / ใหญ่</td></tr><tr><td>เต็มความกว้าง</td><td>เปิด = ปุ่มขยายเต็มแนวนอน</td></tr><tr><td>การจัดตำแหน่ง</td><td>ซ้าย / กลาง / ขวา</td></tr></tbody></table><p><strong>สิ่งที่ปุ่มทำได้เมื่อกด:</strong></p><table tabindex="0"><thead><tr><th>ประเภทการทำงาน</th><th>รายละเอียด</th></tr></thead><tbody><tr><td><strong>บันทึกข้อมูลในออเดอร์</strong></td><td>ตรวจสอบข้อมูลที่กรอกทั้งหมด แล้วบันทึกลงในออเดอร์ปัจจุบัน ใช้สำหรับอัปเดตสถานะหรือเพิ่มข้อมูลในออเดอร์ที่เปิดอยู่</td></tr><tr><td><strong>ไปยังหน้าอื่น</strong></td><td>พาผู้ใช้ไปยังหน้าที่กำหนด เช่น กลับหน้ารายการสถานี หรือไปหน้าติดตามการผลิต กำหนดได้ว่าจะไปหน้าไหน</td></tr><tr><td><strong>ดำเนินการกับข้อมูล</strong></td><td>สั่งให้ระบบทำงาน เช่น สร้างออเดอร์ใหม่จากบิลที่เลือก หรืออัปเดตสถานะชิ้นงาน ระบบจะนำข้อมูลที่กรอกและเลือกไว้ทั้งหมดส่งเข้าระบบโดยอัตโนมัติ</td></tr><tr><td><strong>ยืนยันก่อนทำ</strong></td><td>แสดงกล่องป๊อปอัปให้ยืนยันก่อน แล้วจึงดำเนินการ ป้องกันการกดปุ่มโดยไม่ตั้งใจ</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">ปุ่มสร้างออเดอร์</p><p>ตั้งประเภทการทำงานเป็น <strong>ดำเนินการกับข้อมูล</strong> และเลือกการทำงาน &quot;สร้างออเดอร์ใหม่&quot; ระบบจะนำข้อมูลจากบิลที่เลือกและช่องกรอกต่าง ๆ ไปสร้างออเดอร์ พร้อมโยงชิ้นงานเข้าออเดอร์ให้อัตโนมัติ</p></div><hr><h4 id="สแกน-qr-code-qrscanblock" tabindex="-1">สแกน QR Code (QrScanBlock) <a class="header-anchor" href="#สแกน-qr-code-qrscanblock" aria-label="Permalink to &quot;สแกน QR Code (QrScanBlock)&quot;">​</a></h4><p>ช่องให้พนักงานสแกน QR Code จากกล้องหรือเครื่องสแกน เพื่อโหลดข้อมูลหรือบันทึกการทำงาน</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>ข้อความแสดงเหนือช่องสแกน เช่น &quot;สแกน QR ชิ้นงาน&quot;</td></tr><tr><td>โหมดสแกน</td><td>ดูตารางด้านล่าง</td></tr><tr><td>บันทึกอัตโนมัติหลังสแกน</td><td>เปิด = เมื่อสแกนสำเร็จ ระบบจะบันทึกการเปลี่ยนแปลงที่กำหนดไว้ให้ทันที โดยไม่ต้องกดปุ่มเพิ่ม</td></tr><tr><td>ข้อมูลที่จะบันทึก</td><td>ข้อมูลที่ระบบบันทึกอัตโนมัติ เช่น สถานะ &quot;เริ่มแล้ว&quot; — กำหนดโดย Admin</td></tr><tr><td>ข้อความเมื่อสำเร็จ</td><td>ข้อความที่แสดงให้พนักงานเห็นหลังสแกนสำเร็จ</td></tr><tr><td>เปิดกล้อง</td><td>เปิด = มีปุ่มเปิดกล้องโทรศัพท์/กล้องเว็บแคมเพื่อสแกน</td></tr><tr><td>บังคับเบิกก่อนเริ่ม/เสร็จ</td><td>เปิด = ที่โหมดสแกนเข้าสถานี ต้องมีการเบิกวัสดุโยงกับแผ่นก่อนจึงจะกดเริ่มงานหรือเสร็จสิ้นได้ (เหมาะสถานีตัด)</td></tr></tbody></table><p><strong>โหมดสแกน:</strong></p><table tabindex="0"><thead><tr><th>โหมด</th><th>สิ่งที่เกิดขึ้นเมื่อสแกน</th></tr></thead><tbody><tr><td><strong>โหลดออเดอร์</strong></td><td>ดึงข้อมูลออเดอร์จาก QR มาแสดงในหน้าจอ เพื่อให้บล็อกอื่นแสดงรายละเอียดออเดอร์นั้น</td></tr><tr><td><strong>โหลดบิล</strong></td><td>ดึงข้อมูลบิลจาก QR มาแสดง</td></tr><tr><td><strong>โหลดชิ้นงาน</strong></td><td>ดึงข้อมูลชิ้นงานจาก QR มาแสดง ขนาด ประเภท สถานะ</td></tr><tr><td><strong>สแกนเข้าสถานี</strong></td><td>บันทึกว่าชิ้นงานนี้มาถึงสถานีนี้แล้ว แสดงปุ่มให้พนักงานกด &quot;เริ่มงาน&quot; ต่อ</td></tr><tr><td><strong>สแกนออกสถานี</strong></td><td>บันทึกว่าชิ้นงานนี้ทำเสร็จและออกจากสถานีนี้แล้ว ระบบจะส่งชิ้นงานไปยังสถานีถัดไปโดยอัตโนมัติ</td></tr></tbody></table><hr><h3 id="📊-บล็อกแสดงรายการและรายละเอียด" tabindex="-1">📊 บล็อกแสดงรายการและรายละเอียด <a class="header-anchor" href="#📊-บล็อกแสดงรายการและรายละเอียด" aria-label="Permalink to &quot;📊 บล็อกแสดงรายการและรายละเอียด&quot;">​</a></h3><p>บล็อกกลุ่มนี้ดึงข้อมูลจากระบบมาแสดงบนหน้าจอ และอัปเดตแบบเรียลไทม์</p><hr><h4 id="ตารางรายการ-recordlist" tabindex="-1">ตารางรายการ (RecordList) <a class="header-anchor" href="#ตารางรายการ-recordlist" aria-label="Permalink to &quot;ตารางรายการ (RecordList)&quot;">​</a></h4><p>แสดงรายการข้อมูลในรูปแบบตาราง ข้อมูลอัปเดตอัตโนมัติเมื่อมีการเปลี่ยนแปลง ใช้สำหรับแสดงรายการออเดอร์ที่รอ รายการบิล หรือรายการวัสดุในคลัง</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>ชื่อที่แสดงเป็นหัวตาราง</td></tr><tr><td>ชนิดข้อมูล</td><td>ออเดอร์ / บิล / วัสดุ / ชิ้นงาน / พนักงาน (เลือกชนิดเดียว)</td></tr><tr><td>แสดงสูงสุด</td><td>จำนวนแถวที่แสดง เช่น 5 หรือ 10</td></tr><tr><td>ช่องค้นหา</td><td>เปิด = แสดงช่องค้นหาเหนือตาราง</td></tr><tr><td>กรองเฉพาะสถานีนี้</td><td>เปิด = แสดงเฉพาะชิ้นงานที่อยู่ที่สถานีนี้</td></tr><tr><td>แสดงปุ่ม QR</td><td>เปิด = ทุกแถวมีปุ่มเปิด QR Code</td></tr><tr><td>แสดงลิงก์ใบงาน</td><td>เปิด = ทุกแถวมีลิงก์เปิดใบงานเพื่อพิมพ์</td></tr><tr><td>ซ่อนบิลที่เสร็จแล้ว</td><td>เปิด = ซ่อนบิลที่สร้างออเดอร์ไปแล้ว แสดงเฉพาะบิลที่ยังรอ</td></tr><tr><td>เฉพาะออเดอร์ที่มีงานค้าง</td><td>เปิด = แสดงเฉพาะออเดอร์ที่ยังมีชิ้นงานรอดำเนินการ</td></tr></tbody></table><p><strong>คอลัมน์ที่แสดงในตาราง:</strong></p><p>กำหนดได้ว่าตารางจะแสดงคอลัมน์อะไรบ้าง แต่ละคอลัมน์ต้องระบุ 3 อย่าง:</p><ul><li><strong>ชื่อข้อมูล</strong> — ชื่อข้อมูลในระบบ (ดูตารางด้านล่าง)</li><li><strong>ชื่อหัวคอลัมน์</strong> — ข้อความที่แสดงบนหัวตาราง เช่น &quot;ลูกค้า&quot; หรือ &quot;วันที่&quot;</li><li><strong>ประเภทการแสดงผล</strong> — วิธีแสดงข้อมูล: ข้อความ / ตัวเลข / สถานะ / วันที่ / ป้าย / ราคา</li></ul><p>ตัวอย่างคอลัมน์ที่ใช้บ่อย:</p><table tabindex="0"><thead><tr><th>ชื่อข้อมูล</th><th>ความหมาย</th><th>ประเภทที่แนะนำ</th></tr></thead><tbody><tr><td><code>code</code></td><td>รหัสออเดอร์/บิล</td><td>ข้อความ</td></tr><tr><td><code>customer.name</code></td><td>ชื่อลูกค้า</td><td>ข้อความ</td></tr><tr><td><code>status</code></td><td>สถานะ</td><td>สถานะ</td></tr><tr><td><code>createdAt</code></td><td>วันที่สร้าง</td><td>วันที่</td></tr><tr><td><code>quantity</code></td><td>จำนวน</td><td>ตัวเลข</td></tr><tr><td><code>totalPrice</code></td><td>ราคารวม</td><td>ราคา</td></tr><tr><td><code>material.name</code></td><td>ชื่อวัสดุ</td><td>ข้อความ</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">เมื่อคลิกแถวในตาราง</p><p>ข้อมูลแถวที่คลิกจะถูกโหลดเข้าระบบ — บล็อก &quot;รายละเอียด&quot; และ &quot;หัวเรื่อง&quot; ที่ตั้งค่าให้แสดงข้อมูลอัตโนมัติจะอัปเดตทันที สามารถกำหนดให้คลิกแล้วพาไปยังหน้าอื่นก็ได้</p></div><hr><h4 id="รายละเอียดข้อมูล-recorddetail" tabindex="-1">รายละเอียดข้อมูล (RecordDetail) <a class="header-anchor" href="#รายละเอียดข้อมูล-recorddetail" aria-label="Permalink to &quot;รายละเอียดข้อมูล (RecordDetail)&quot;">​</a></h4><p>แสดงรายละเอียดข้อมูลแบบแถวคู่ (ชื่อ: ค่า) เหมาะสำหรับแสดงข้อมูลครบถ้วนของออเดอร์หรือบิลที่เลือกอยู่ในปัจจุบัน</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อป้ายกำกับ</td><td>หัวข้อของส่วนรายละเอียด</td></tr><tr><td>ชนิดข้อมูล</td><td>ออเดอร์ / บิล / ชิ้นงาน ฯลฯ</td></tr></tbody></table><p><strong>ฟิลด์ที่แสดง:</strong></p><p>เลือกได้ว่าจะแสดงข้อมูลอะไรบ้าง แต่ละฟิลด์ระบุ:</p><ul><li><strong>ชื่อข้อมูล</strong> — ข้อมูลในระบบที่ต้องการแสดง</li><li><strong>ชื่อป้ายกำกับ</strong> — ชื่อที่แสดงข้างหน้าค่า เช่น &quot;ลูกค้า:&quot; หรือ &quot;ราคารวม:&quot;</li><li><strong>ประเภทการแสดงผล</strong> — ข้อความ / ตัวเลข / สถานะ / วันที่ / ป้าย / ราคา</li></ul><hr><h3 id="🏭-บล็อกเฉพาะสถานีงาน" tabindex="-1">🏭 บล็อกเฉพาะสถานีงาน <a class="header-anchor" href="#🏭-บล็อกเฉพาะสถานีงาน" aria-label="Permalink to &quot;🏭 บล็อกเฉพาะสถานีงาน&quot;">​</a></h3><p>บล็อกกลุ่มนี้ออกแบบมาสำหรับการทำงานในสถานีโดยเฉพาะ</p><hr><h4 id="เลือกลําดับสถานี-stationsequencepicker" tabindex="-1">เลือกลำดับสถานี (StationSequencePicker) <a class="header-anchor" href="#เลือกลําดับสถานี-stationsequencepicker" aria-label="Permalink to &quot;เลือกลำดับสถานี (StationSequencePicker)&quot;">​</a></h4><p>บล็อกสำหรับเลือกและเรียงลำดับสถานีที่ชิ้นงานต้องผ่าน เมื่อพนักงานสร้างออเดอร์ ระบบจะนำลำดับสถานีที่เลือกไว้ไปกำหนดเส้นทางการผลิตของชิ้นงานทุกชิ้น</p><p><strong>วิธีใช้งาน:</strong></p><ol><li>บล็อกแสดงรายชื่อสถานีทั้งหมดที่มีในโรงงาน</li><li>กดเลือกสถานีที่ต้องการ</li><li>ลากเพื่อเรียงลำดับ</li><li>หรือเลือก Preset สำเร็จรูปเพื่อความรวดเร็ว</li></ol><p><strong>Preset สำเร็จรูป:</strong></p><table tabindex="0"><thead><tr><th>Preset</th><th>เหมาะกับงาน</th></tr></thead><tbody><tr><td>กระจกนิรภัย</td><td>งานอบกระจกแบบ Tempered</td></tr><tr><td>กระจกลามิเนต</td><td>งานประกบฟิล์มกลาง</td></tr><tr><td>กระจกใส</td><td>งานตัดและขัดขอบธรรมดา</td></tr><tr><td>กระจกเจาะ</td><td>งานที่ต้องเจาะรูหรือขอบ</td></tr><tr><td>กระบวนการเต็ม</td><td>ผ่านทุกสถานี</td></tr></tbody></table><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อหัวข้อ</td><td>ข้อความที่แสดงด้านบนของบล็อก</td></tr><tr><td>ชื่ออ้างอิง</td><td>ชื่อที่ระบบใช้บันทึกลำดับสถานีที่เลือก เพื่อส่งให้ปุ่มสร้างออเดอร์นำไปใช้</td></tr></tbody></table><hr><h4 id="ประวัติการผลิต-stationhistory" tabindex="-1">ประวัติการผลิต (StationHistory) <a class="header-anchor" href="#ประวัติการผลิต-stationhistory" aria-label="Permalink to &quot;ประวัติการผลิต (StationHistory)&quot;">​</a></h4><p>แสดงประวัติชิ้นงานที่ผ่านสถานีนี้ รวมถึงชิ้นงานที่ทำเสร็จแล้วแต่ยังรอสแกนออก</p><p><strong>สิ่งที่แสดง:</strong></p><ul><li>ชิ้นงานที่ทำเสร็จแล้วแต่ยังไม่ได้สแกนออก (รอ Scan-out) — แสดงชัดเจนเพื่อให้พนักงานจัดการ</li><li>ประวัติชิ้นงานที่ผ่านสถานีนี้ทั้งหมด จัดกลุ่มตามออเดอร์</li></ul><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ชื่อหัวข้อ</td><td>ข้อความที่แสดงด้านบน</td></tr><tr><td>แสดงสูงสุด</td><td>จำนวนแถวประวัติ</td></tr></tbody></table><hr><h4 id="คิวงานปัจจุบัน-stationqueueblock" tabindex="-1">คิวงานปัจจุบัน (StationQueueBlock) <a class="header-anchor" href="#คิวงานปัจจุบัน-stationqueueblock" aria-label="Permalink to &quot;คิวงานปัจจุบัน (StationQueueBlock)&quot;">​</a></h4><p>แสดงชิ้นงานที่กำลังอยู่ในสถานีนี้ จัดกลุ่มตามออเดอร์ พนักงานสามารถดำเนินการแต่ละชิ้นได้จากบล็อกนี้โดยตรง</p><p><strong>การจัดโซนในคิว</strong></p><ul><li><strong>งานด่วน</strong> — ออเดอร์ที่มีความเร่งด่วนสูง (เช่นใกล้กำหนดส่งระดับวิกฤต) แสดงด้านบนเพื่อให้เห็นก่อน</li><li><strong>คิวงานถัดไป</strong> — งานอื่น ๆ ที่อยู่ที่สถานีนี้ รวมถึงที่กำลังทำหรือทำเสร็จแล้วแต่ยังอยู่ในคิวของสถานี (ไม่ถูกดันขึ้นไปบนสุดเพียงเพราะกดเริ่ม/เสร็จ)</li></ul><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>บังคับเบิกก่อนเริ่ม/เสร็จ</td><td>เปิด = ต้องเบิกวัสดุโยงกับแผ่นก่อนจึงจะกดเริ่มงานหรือเสร็จสิ้นได้</td></tr></tbody></table><p><strong>สิ่งที่แสดงและทำได้:</strong></p><ul><li>รายการชิ้นงานทั้งหมดที่อยู่ในสถานี จัดกลุ่มตามออเดอร์</li><li>ปุ่ม <strong>สแกนเข้า</strong> — บันทึกว่าชิ้นงานมาถึงสถานีแล้ว</li><li>ปุ่ม <strong>เริ่มงาน</strong> — บันทึกเวลาเริ่มทำงาน</li><li>ปุ่ม <strong>เสร็จสิ้น</strong> — บันทึกว่าทำงานเสร็จแล้ว</li><li>ปุ่ม QR Code — เปิด QR ของชิ้นงานเพื่อพิมพ์หรือส่งต่อ</li><li>ข้อมูลอัปเดตอัตโนมัติตลอดเวลา</li><li>รองรับการสแกนด้วยกล้อง</li></ul><hr><h4 id="ตรวจสอบ-qc-qc-inspector" tabindex="-1">ตรวจสอบ QC (QC Inspector) <a class="header-anchor" href="#ตรวจสอบ-qc-qc-inspector" aria-label="Permalink to &quot;ตรวจสอบ QC (QC Inspector)&quot;">​</a></h4><p>บล็อกสำหรับสถานีตรวจคุณภาพ: แสดงรายการตรวจ (Checklist) ให้พนักงานติ๊กครบแล้วกด <strong>ผ่าน QC</strong> หรือ <strong>ไม่ผ่าน</strong> (พร้อมเหตุผลเมื่อไม่ผ่าน)</p><p><strong>การทำงานกับ API</strong></p><ul><li>ระบบจะส่งคำสั่งสแกนไปยัง API ตามลำดับที่ฝั่งเซิร์ฟเวอร์กำหนด รวมถึงการ <strong>เริ่มงาน</strong> และ <strong>เสร็จสิ้น</strong> ที่สถานี QC ก่อนบันทึกผล <strong>ผ่าน / ไม่ผ่าน</strong> — เพราะ API กำหนดว่าต้องจบขั้นตอนงานที่สถานีก่อนจึงจะบันทึก QC ได้</li><li>สถานีถัดไปของแผ่นหลังแต่ละขั้นเป็นข้อมูลที่ API ตอบกลับมา ไม่ได้คำนวณแยกในหน้าเว็บ</li></ul><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>หัวข้อ</td><td>ข้อความหัวบล็อก</td></tr><tr><td>Checklist (JSON)</td><td>รายการข้อตรวจที่ให้ติ๊ก</td></tr><tr><td>แสดงคำอธิบาย</td><td>เปิด/ปิดส่วนคำอธิบายเพิ่มเติม</td></tr></tbody></table><hr><h4 id="สต็อกวัสดุ-inventorystockblock" tabindex="-1">สต็อกวัสดุ (InventoryStockBlock) <a class="header-anchor" href="#สต็อกวัสดุ-inventorystockblock" aria-label="Permalink to &quot;สต็อกวัสดุ (InventoryStockBlock)&quot;">​</a></h4><p>แสดงสต็อกวัสดุในคลัง ณ ปัจจุบัน เหมาะสำหรับสถานีที่ต้องตรวจสอบว่าวัสดุพร้อมก่อนรับงาน</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>ตัวเลือก</th></tr></thead><tbody><tr><td>ชื่อหัวข้อ</td><td>ข้อความแสดงด้านบน</td></tr><tr><td>แสดงสูงสุด</td><td>จำนวนรายการ</td></tr><tr><td>กรองตามสถานะ</td><td>ทั้งหมด / เฉพาะที่ใกล้หมด / เฉพาะที่หมดแล้ว</td></tr><tr><td>ช่องค้นหา</td><td>เปิด/ปิด</td></tr></tbody></table><hr><h4 id="แผงปล่อยออเดอร์-orderreleasepanel" tabindex="-1">แผงปล่อยออเดอร์ (OrderReleasePanel) <a class="header-anchor" href="#แผงปล่อยออเดอร์-orderreleasepanel" aria-label="Permalink to &quot;แผงปล่อยออเดอร์ (OrderReleasePanel)&quot;">​</a></h4><p>แผงสำหรับ Admin หรือ Manager ใช้ตรวจสอบและปล่อยออเดอร์เข้าสายการผลิต ระบบจะแสดงข้อมูลที่จำเป็นในการตัดสินใจ เช่น สต็อกวัสดุเพียงพอหรือไม่ ข้อมูลลูกค้าครบหรือไม่ ราคาถูกต้องหรือไม่</p><p><strong>สิ่งที่แสดงและทำได้:</strong></p><ul><li>รายการออเดอร์ที่รอปล่อยสู่การผลิต</li><li>สัญลักษณ์แสดงว่าออเดอร์นั้น ✓ พร้อม หรือ ✗ มีปัญหา (สต็อก/ราคา/ข้อมูล)</li><li>ปุ่มยืนยันปล่อยออเดอร์เข้าสายการผลิต</li><li>ข้อมูลอัปเดตอัตโนมัติ</li></ul><hr><h4 id="พิมพ์สติกเกอร์-stickerprintblock" tabindex="-1">พิมพ์สติกเกอร์ (StickerPrintBlock) <a class="header-anchor" href="#พิมพ์สติกเกอร์-stickerprintblock" aria-label="Permalink to &quot;พิมพ์สติกเกอร์ (StickerPrintBlock)&quot;">​</a></h4><p>ปุ่มสำหรับพิมพ์สติกเกอร์ QR Code ติดชิ้นงาน เมื่อกดจะแสดงรายการ Template สติกเกอร์ที่สร้างไว้ ให้เลือกแล้วพิมพ์</p><table tabindex="0"><thead><tr><th>ค่าตั้งค่า</th><th>รายละเอียด</th></tr></thead><tbody><tr><td>ข้อความบนปุ่ม</td><td>เช่น &quot;พิมพ์สติกเกอร์&quot;</td></tr></tbody></table><p><strong>การทำงาน:</strong></p><ol><li>พนักงานกดปุ่ม</li><li>ระบบเปิดหน้าต่างให้เลือก Template สติกเกอร์</li><li>ดึงข้อมูลชิ้นงานทุกชิ้นในออเดอร์/บิลที่เลือกอยู่</li><li>แสดงตัวอย่างสติกเกอร์พร้อมข้อมูลจริง</li><li>พนักงานกดพิมพ์</li></ol><hr><h2 id="ข้อมูลที่แสดงได้อัตโนมัติ" tabindex="-1">ข้อมูลที่แสดงได้อัตโนมัติ <a class="header-anchor" href="#ข้อมูลที่แสดงได้อัตโนมัติ" aria-label="Permalink to &quot;ข้อมูลที่แสดงได้อัตโนมัติ&quot;">​</a></h2><p>บล็อกที่รองรับ <strong>แสดงข้อมูลอัตโนมัติ</strong> สามารถเลือกข้อมูลต่อไปนี้ได้:</p><h3 id="จากออเดอร์ที่เลือกอยู่" tabindex="-1">จากออเดอร์ที่เลือกอยู่ <a class="header-anchor" href="#จากออเดอร์ที่เลือกอยู่" aria-label="Permalink to &quot;จากออเดอร์ที่เลือกอยู่&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ชื่อข้อมูล</th><th>แสดงอะไร</th></tr></thead><tbody><tr><td><code>order.code</code></td><td>รหัสออเดอร์</td></tr><tr><td><code>order.customer.name</code></td><td>ชื่อลูกค้า</td></tr><tr><td><code>order.quantity</code></td><td>จำนวนชิ้นงานทั้งหมด</td></tr><tr><td><code>order.status</code></td><td>สถานะออเดอร์ปัจจุบัน</td></tr><tr><td><code>order.totalPrice</code></td><td>ราคารวม</td></tr><tr><td><code>order.dueDate</code></td><td>วันกำหนดส่ง</td></tr></tbody></table><h3 id="จากบิลที่เลือกอยู่" tabindex="-1">จากบิลที่เลือกอยู่ <a class="header-anchor" href="#จากบิลที่เลือกอยู่" aria-label="Permalink to &quot;จากบิลที่เลือกอยู่&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ชื่อข้อมูล</th><th>แสดงอะไร</th></tr></thead><tbody><tr><td><code>request.code</code></td><td>รหัสบิล</td></tr><tr><td><code>request.customer.name</code></td><td>ชื่อลูกค้า</td></tr><tr><td><code>request.details.quantity</code></td><td>จำนวนจากบิล</td></tr></tbody></table><h3 id="จากชิ้นงานที่สแกน" tabindex="-1">จากชิ้นงานที่สแกน <a class="header-anchor" href="#จากชิ้นงานที่สแกน" aria-label="Permalink to &quot;จากชิ้นงานที่สแกน&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ชื่อข้อมูล</th><th>แสดงอะไร</th></tr></thead><tbody><tr><td><code>pane.glassType</code></td><td>ประเภทกระจก</td></tr><tr><td><code>pane.status</code></td><td>สถานะชิ้นงาน</td></tr><tr><td><code>pane.width</code></td><td>ความกว้าง</td></tr><tr><td><code>pane.height</code></td><td>ความสูง</td></tr></tbody></table><h3 id="จากข้อมูลที่กรอกในฟอร์ม" tabindex="-1">จากข้อมูลที่กรอกในฟอร์ม <a class="header-anchor" href="#จากข้อมูลที่กรอกในฟอร์ม" aria-label="Permalink to &quot;จากข้อมูลที่กรอกในฟอร์ม&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ชื่อข้อมูล</th><th>แสดงอะไร</th></tr></thead><tbody><tr><td><code>form.ชื่ออ้างอิง</code></td><td>ค่าที่พนักงานกรอกในช่องที่มีชื่ออ้างอิงนั้น</td></tr></tbody></table><hr><h2 id="วิธีนําแบบสถานีไปใช้กับสถานี" tabindex="-1">วิธีนำแบบสถานีไปใช้กับสถานี <a class="header-anchor" href="#วิธีนําแบบสถานีไปใช้กับสถานี" aria-label="Permalink to &quot;วิธีนำแบบสถานีไปใช้กับสถานี&quot;">​</a></h2>',161)),a(o,null,{default:e(()=>[...r[2]||(r[2]=[t("div",{class:"step","data-step":"1"},[t("h4",null,"ไปที่รายการสถานี"),t("p",null,[d("เข้าเมนู "),t("strong",null,"สถานี"),d(" แล้วหาสถานีที่ต้องการ")])],-1),t("div",{class:"step","data-step":"2"},[t("h4",null,"แก้ไขสถานี"),t("p",null,[d("กดปุ่ม "),t("strong",null,"แก้ไข"),d(" บนการ์ดสถานีนั้น")])],-1),t("div",{class:"step","data-step":"3"},[t("h4",null,"เลือกแบบสถานี"),t("p",null,[d("เลือก "),t("strong",null,"แบบหน้าจอ"),d(" ที่ต้องการจาก Dropdown รายการ")])],-1),t("div",{class:"step","data-step":"4"},[t("h4",null,"บันทึก"),t("p",null,[d("กด "),t("strong",null,"บันทึก"),d(" — สถานีนี้จะแสดงหน้าจอตามแบบที่เลือกทันที")])],-1)])]),_:1}),r[6]||(r[6]=t("div",{class:"tip custom-block"},[t("p",{class:"custom-block-title"},"แบบเดียวใช้ได้หลายสถานี"),t("p",null,"แบบสถานี 1 แบบสามารถนำไปใช้กับสถานีหลายสถานีได้ เหมาะสำหรับสถานีที่ทำงานเหมือนกัน เช่น สถานีขัดขอบ A และ สถานีขัดขอบ B")],-1))]))}});export{q as __pageData,g as default};
